import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"流力长靴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/流力长靴.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/流力长靴.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/流力长靴.md"};function l(_,a,i,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"流力长靴",tabindex:"-1"},[s("流力长靴 "),e("a",{class:"header-anchor",href:"#流力长靴","aria-label":'Permalink to "流力长靴"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="流力长靴-1" tabindex="-1">流力长靴 <a class="header-anchor" href="#流力长靴-1" aria-label="Permalink to &quot;流力长靴&quot;">​</a></h1><p>流力长靴<br> 占据鞋袜位<br> D+1000<br> 魔幻本质<br> 来自名为阿菲亚世界的魔法长靴，寄宿着元素魔法的力量，在美丽而危险的阿菲亚，魔法师们依靠这种长靴在地面高速移动，翻越山岭，渡过湖面，或是逃离那些足以杀死自己的东西。<br> 描述：<br> 一双做工精良且坚固的皮质长靴，每只靴子的靴筒部位，都有着四圈如同丝带一般魔纹阵列，这些魔纹会随着靴子所处的环境变化，给与穿戴者翻山越岭的助力。<br> 效果：<br> 流力：只要穿上这双靴子，每一次踏步，你都能感受到脚下传来源源不断的推力；当人物在地面奔跑时，靴子将被土黄色魔法力量笼罩，这使得人物的地面移动速度提升10米。<br> 凭风：人物可以凭借风的力量，跳出惊人的距离，从而快速在山岭或者建筑之间移动；当人物跳跃离地时，绿色的狂风将缠绕流力长靴，这使得人物可以使用跳跃检定时视为进行了助跑。同时人物免疫自然坠落带来的伤害。<br> 岩攀：当人物处于水平或者垂直于地面的岩壁，或者其他石头土壤组成的平面时，靴子将泛起橙黄色的光，这使得人物的重力被协调至垂直脚下的平面，这视为人物获得等同于地面移动速度的攀爬速度。<br> 浪划：当人物处于水域表面时，靴子将操纵水体形成冲浪板的形状，这使得人物获得在水面自由移动的能力，当人物离开水域时，水组成的冲浪板将无害消散。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
